import{_ as a,c as e,o as m,b as t}from"./app.1117c437.js";const c='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 10","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 10","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-01T00:00:00.000Z"},"headers":[{"level":2,"title":"\u041A\u043E\u043D\u0435\u0446 \u0413\u043B\u0430\u0432\u044B II","slug":"\u043A\u043E\u043D\u0435\u0446-\u0433n\u0430\u0432\u044B-ii"}],"relativePath":"texts/shiva-sutra-vimarshini/2/10/index.md"}',p={},i=t('<div class="stanza"><a href="#s2.10" id="s2.10" class="num">2.10</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u094D\u0935\u0947\u0935\u0902 \u0938\u0924\u0924\u093E\u0935\u0939\u093F\u0924\u094B \u0928 \u092D\u0935\u0924\u093F \u0924\u0926\u093E \u091C\u094D\u091E\u093E\u0928\u0935\u0924\u094B\u093D\u092A\u094D\u092F\u0938\u094D\u092F\u093E\u0935\u0927\u093E\u0928\u093E\u0935\u0932\u0947\u092A\u093E\u0924\u094D\u2014</p><blockquote><p><strong>\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u0902\u0939\u093E\u0930\u0947 \u0924\u0926\u0941\u0924\u094D\u0925\u0938\u094D\u0935\u092A\u094D\u0928\u0926\u0930\u094D\u0936\u0928\u092E\u094D\u0965\u0967\u0966\u0965</strong></p></blockquote><p>\u092A\u094D\u0930\u094B\u0915\u094D\u0924\u091C\u094D\u091E\u093E\u0928\u0938\u094D\u092B\u093E\u0930\u0930\u0942\u092A\u093E\u092F\u093E\u0903 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u092F\u093E\u0903 \u0938\u0902\u0939\u093E\u0930\u0947 \u0928\u093F\u092E\u091C\u094D\u091C\u0928\u0947 \u0924\u0926\u0941\u0924\u094D\u0925\u0938\u094D\u092F \u0915\u094D\u0930\u092E\u093E\u0924\u094D\u0915\u094D\u0930\u092E\u0928\u094D\u092F\u0915\u094D\u0915\u0943\u0924\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u0902\u0938\u094D\u0915\u093E\u0930\u0938\u094D\u092F \u0938\u094D\u0935\u092A\u094D\u0928\u0938\u094D\u092F \u092D\u0947\u0926\u092E\u092F\u0938\u094D\u092F \u0935\u093F\u0915\u0932\u094D\u092A\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0930\u0942\u092A\u0938\u094D\u092F \u0926\u0930\u094D\u0936\u0928\u0902 \u0938\u094D\u092B\u0941\u091F\u092E\u0941\u0928\u094D\u092E\u091C\u094D\u091C\u0928\u0902 \u092D\u0935\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0947</p><blockquote><p>\u0928 \u091A\u0948\u0924\u0926\u092A\u094D\u0930\u0938\u0928\u094D\u0928\u0947\u0928 \u0936\u0919\u094D\u0915\u0930\u0947\u0923\u094B\u092A\u0926\u093F\u0936\u094D\u092F\u0924\u0947\u0964<br> \u0915\u0925\u091E\u094D\u091A\u093F\u0926\u0941\u092A\u0926\u093F\u0937\u094D\u091F\u0947\u093D\u092A\u093F \u0935\u093E\u0938\u0928\u093E \u0928\u0948\u0935 \u091C\u093E\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F</p><blockquote><p>\u0935\u093E\u0938\u0928\u093E\u092E\u093E\u0924\u094D\u0930\u0932\u093E\u092D\u0947\u093D\u092A\u093F \u092F\u094B\u093D\u092A\u094D\u0930\u092E\u0924\u094D\u0924\u094B \u0928 \u091C\u093E\u092F\u0924\u0947\u0964<br> \u0924\u092E\u0928\u093F\u0924\u094D\u092F\u0947\u0937\u0941 \u092D\u094B\u0917\u0947\u0937\u0941 \u092F\u094B\u091C\u092F\u0928\u094D\u0924\u093F \u0935\u093F\u0928\u093E\u092F\u0915\u093E\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0926\u0947\u0924\u0924\u094D</p><blockquote><p>\u0905\u0928\u094D\u092F\u0925\u093E \u0924\u0941 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u093E \u0938\u094D\u092F\u093E\u0924\u094D\u0938\u0943\u0937\u094D\u0924\u093F\u0938\u094D\u0924\u0926\u094D\u0927\u0930\u094D\u092E\u0915\u0924\u094D\u0935\u0924\u0903\u0964<br> \u0938\u0924\u0924\u0902 \u0932\u094C\u0915\u093F\u0915\u0938\u094D\u092F\u0947\u0935 \u091C\u093E\u0917\u094D\u0930\u0924\u094D\u0938\u094D\u0935\u092A\u094D\u0928\u092A\u0926\u0926\u094D\u0935\u092F\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0964 \u0905\u0924\u0936\u094D\u091A \u0928\u093F\u0924\u094D\u092F\u0902 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u092A\u0930\u0947\u0923\u0948\u0935 \u092F\u094B\u0917\u093F\u0928\u093E \u092D\u093E\u0935\u094D\u092F\u092E\u093F\u0924\u094D\u092F\u0941\u092A\u0926\u093F\u0937\u094D\u091F\u0902 \u092D\u0935\u0924\u093F\u0964 \u092F\u0925\u094B\u0915\u094D\u0924\u092E\u094D</p><blockquote><p>\u0924\u0938\u094D\u092E\u093E\u0928\u094D\u0928 \u0924\u0947\u0937\u0941 \u0938\u0902\u0938\u0915\u094D\u0924\u093F\u0902 \u0915\u0941\u0930\u094D\u0935\u0940\u0924\u094B\u0924\u094D\u0924\u092E\u0935\u093E\u091E\u094D\u091B\u092F\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092A\u0942\u0930\u094D\u0935\u0947\u0964 \u0936\u094D\u0930\u093F\u0938\u094D\u092A\u0928\u094D\u0926\u0947\u093D\u092A\u093F</p><blockquote><p>\u0905\u0924\u0903 \u0938\u0924\u0924\u092E\u0941\u0926\u094D\u092F\u0941\u0915\u094D\u0924\u0903 \u0938\u094D\u092A\u0928\u094D\u0926\u0924\u0924\u094D\u0924\u094D\u0935\u0935\u093F\u0935\u093F\u0915\u094D\u0924\u092F\u0947\u0964<br> \u091C\u093E\u0917\u094D\u0930\u0926\u0947\u0935 \u0928\u093F\u091C\u0902 \u092D\u093E\u0935\u092E\u091A\u093F\u0930\u0947\u0923\u093E\u0927\u093F\u0917\u091A\u094D\u091B\u0924\u093F\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0935\u0902 \u091A\u093F\u0924\u094D\u0924\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u0903 (\u0968-\u0967) \u0907\u0924\u094D\u092F\u0924\u0903 \u092A\u094D\u0930\u092D\u0943\u0924\u093F \u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u092E\u0941\u0926\u094D\u0930\u093E\u0935\u0940\u0930\u094D\u092F\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093F\u092A\u094D\u0930\u0927\u093E\u0928\u092E\u094D</p><blockquote><p>\u0909\u091A\u094D\u091A\u093E\u0930\u0930\u0939\u093F\u0924\u0902 \u0935\u0938\u094D\u0924\u0941 \u091A\u0947\u0924\u0938\u0948\u0935 \u0935\u093F\u091A\u093F\u0928\u094D\u0924\u092F\u0928\u094D\u0964<br> \u092F\u0902 \u0938\u092E\u093E\u0935\u0947\u0936\u092E\u093E\u092A\u094D\u0928\u094B\u0924\u093F \u0936\u093E\u0915\u094D\u0924\u0903 \u0938\u094B\u093D\u0924\u094D\u0930\u093E\u092D\u093F\u0927\u0940\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u092E\u094D\u0928\u093E\u0924\u0902 \u0936\u093E\u0915\u094D\u0924\u094B\u092A\u093E\u092F\u0902 \u0935\u093F\u0935\u093F\u091A\u094D\u092F\u093E\u0935\u0927\u093E\u0928\u093E\u0935\u0932\u093F\u092A\u094D\u0924\u0902 \u092A\u094D\u0930\u0924\u093F \u0935\u093F\u0926\u094D\u092F\u093E\u0938\u0902\u0939\u093E\u0930\u0947 \u0924\u0926\u0941\u0924\u094D\u0925\u0938\u094D\u0935\u092A\u094D\u0928\u0926\u0930\u094D\u0936\u0928\u092E\u094D (\u0968-\u0967\u0966) \u0907\u0924\u093F \u0938\u0942\u0924\u094D\u0930\u0947\u0923\u0948\u0924\u0926\u0928\u0941\u0937\u0919\u094D\u0917\u0947\u0923\u093E\u0923\u0935\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u0928\u0938\u094D\u092F\u093E\u0935\u0915\u093E\u0936\u094B \u0926\u0924\u094D\u0924\u0903\u0964 \u0907\u0924\u093F \u0936\u093F\u0935\u092E\u094D\u0965\u0967\u0966\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tveva\u1E41 satat\u0101vahito na bhavati tad\u0101 j\xF1\u0101navato&#39;pyasy\u0101vadh\u0101n\u0101valep\u0101t\u2014</p><blockquote><p><strong>Vidy\u0101sa\u1E41h\u0101re tadutthasvapnadar\u015Banam||10||</strong></p></blockquote><p>Proktaj\xF1\u0101nasph\u0101rar\u016Bp\u0101y\u0101\u1E25 \u015Buddhavidy\u0101y\u0101\u1E25 sa\u1E41h\u0101re nimajjane tadutthasya kram\u0101tkramanyakk\u1E5Btavidy\u0101sa\u1E41sk\u0101rasya svapnasya bhedamayasya vikalpaprapa\xF1car\u016Bpasya dar\u015Bana\u1E41 sphu\u1E6Damunmajjana\u1E41 bhavati| Tadukta\u1E41 \u015Br\u012Bm\u0101lin\u012Bvijaye</p><blockquote><p>Na caitadaprasannena \u015Ba\u1E45kare\u1E47opadi\u015Byate|<br> Katha\xF1cidupadi\u1E63\u1E6De&#39;pi v\u0101san\u0101 naiva j\u0101yate||</p></blockquote><p>ityupakramya</p><blockquote><p>V\u0101san\u0101m\u0101tral\u0101bhe&#39;pi yo&#39;pramatto na j\u0101yate|<br> Tamanitye\u1E63u bhoge\u1E63u yojayanti vin\u0101yak\u0101\u1E25||</p></blockquote><p>iti| Tadetat</p><blockquote><p>Anyath\u0101 tu svatantr\u0101 sy\u0101ts\u1E5B\u1E63tistaddharmakatvata\u1E25|<br> Satata\u1E41 laukikasyeva j\u0101gratsvapnapadadvaye||</p></blockquote><p>ityanena spande sa\u1E45g\u1E5Bh\u012Btam| Ata\u015Bca nitya\u1E41 \u015Buddhavidy\u0101vimar\u015Banapare\u1E47aiva yogin\u0101 bh\u0101vyamityupadi\u1E63\u1E6Da\u1E41 bhavati| Yathoktam</p><blockquote><p>Tasm\u0101nna te\u1E63u sa\u1E41sakti\u1E41 kurv\u012Btottamav\u0101\xF1chay\u0101|</p></blockquote><p>iti \u015Br\u012Bp\u016Brve| \u015Arispande&#39;pi</p><blockquote><p>Ata\u1E25 satatamudyukta\u1E25 spandatattvaviviktaye|<br> J\u0101gradeva nija\u1E41 bh\u0101vamacire\u1E47\u0101dhigacchati||</p></blockquote><p>iti| Eva\u1E41 citta\u1E41 mantra\u1E25 (2-1) ityata\u1E25 prabh\u1E5Bti mantrav\u012Bryamudr\u0101v\u012Bry\u0101nusandhipradh\u0101nam</p><blockquote><p>Ucc\u0101rarahita\u1E41 vastu cetasaiva vicintayan|<br> Ya\u1E41 sam\u0101ve\u015Bam\u0101pnoti \u015B\u0101kta\u1E25 so&#39;tr\u0101bhidh\u012Byate||</p></blockquote><p>ity\u0101mn\u0101ta\u1E41 \u015B\u0101ktop\u0101ya\u1E41 vivicy\u0101vadh\u0101n\u0101valipta\u1E41 prati vidy\u0101sa\u1E41h\u0101re tadutthasvapnadar\u015Banam (2-10) iti s\u016Btre\u1E47aitadanu\u1E63a\u1E45ge\u1E47\u0101\u1E47avop\u0101yapratip\u0101danasy\u0101vak\u0101\u015Bo datta\u1E25| Iti \u015Bivam||10||</p></div><hr><p>\u041D\u043E <em>(tu)</em> \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [Yog\u012B] <em>(bhavati)</em> \u043D\u0435 <em>(na)</em> \u0441\u0442\u043E\u043B\u044C <em>(evam)</em> \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u0435\u043D <em>(avahita\u1E25)</em> \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(satata)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 [\u044D\u0442\u043E\u0433\u043E] \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E [\u0441\u0432\u043E\u0435 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F] <em>(j\xF1\u0101navata\u1E25)</em>, [\u0441\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F \u0442\u043E, \u0447\u0435\u043C\u0443 \u0443\u0447\u0438\u0442 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C,] \u0438\u0437-\u0437\u0430 \u0443\u043C\u0435\u043D\u044C\u0448\u0435\u043D\u0438\u044F, \u0438\u043B\u0438 \u043E\u0441\u043B\u0430\u0431\u043B\u0435\u043D\u0438\u044F <em>(avalep\u0101t)</em> \u0435\u0433\u043E <em>(asya)</em> \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F <em>(avadh\u0101na)</em>\u2014</p><blockquote><p><strong>\u041F\u0440\u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0438 <em>(sa\u1E41h\u0101re)</em> [\u0427\u0438\u0441\u0442\u043E\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101)</em>, (\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442) \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em> \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 [\u043A\u0430\u043A \u0432\u043E \u0441\u043D\u0435] <em>(svapna)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0445 (uttha)_ \u0438\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E <em>(tad)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C, &quot;\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0445 \u0438\u0437-\u0437\u0430 \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F&quot;]||10||</strong></p></blockquote><p>\u041F\u0440\u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0438 <em>(sa\u1E41h\u0101re)</em> [\u0438\u043B\u0438] \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u0438 \u0432\u043E \u043C\u0440\u0430\u043A <em>(nimajjane)</em> \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F <em>(\u015Buddha-vidy\u0101y\u0101\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(r\u016Bp\u0101y\u0101\u1E25)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435\u043C <em>(sph\u0101ra)</em> \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0433\u043E <em>(prokta)</em> \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em> --\u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0433\u043E \u0432 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435--<sup>1</sup></p><p>, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em>, [\u0438\u043B\u0438] \u044F\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(sphu\u1E6Dam)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(unmajjanam)</em> svapna -- \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438-- <em>(svapnasya)</em>, \u0442.\u0435. \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u044F <em>(prapa\xF1ca)</em>, \u043F\u043E\u043B\u043D\u043E\u0433\u043E <em>(mayasya)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439 <em>(bheda)</em> (\u0438) \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 <em>(vikalpa)</em> [\u043A\u0430\u043A \u0432\u043E \u0441\u043D\u0435. \u042D\u0442\u043E\u0442 svapna] \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0438\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E <em>(tad-utthasya)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0435 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F <em>(sa\u1E41sk\u0101rasya)</em> [\u0427\u0438\u0441\u0442\u043E\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101)</em> \u0443\u0433\u0430\u0441\u0430\u044E\u0442 <em>(nyakk\u1E5Bta)</em> \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E <em>(kram\u0101t-krama)</em><sup>2</sup> |</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C M\u0101lin\u012Bvijayatantra <em>(\u015Br\u012B-m\u0101lin\u012Bvijaye)</em> [\u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C], \u043D\u0430\u0447\u0438\u043D\u0430\u044F [\u0441\u043E \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0433\u043E] <em>(upakramya)</em>, [\u043A\u043E\u0433\u0434\u0430 \u041E\u043D \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0438 \u015Aivat\u0101, \u0438\u043B\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u015Aiva, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u0435\u0442 \u0441 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F]:</p><blockquote><p>&quot;\u042D\u0442\u043E\u043C\u0443 <em>(etad)</em> \u0443\u0447\u0438\u0442 <em>(upadi\u015Byate)</em> \u015Aa\u1E45kara --\u0442.\u0435. \u015Aiva-- <em>(\u015Ba\u1E45kare\u1E47a)</em>, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0434\u043E\u0432\u043E\u043B\u0435\u043D <em>(na ca... aprasannena)</em>!<sup>3</sup> [\u041D\u043E] \u0434\u0430\u0436\u0435 <em>(api)</em>, \u043A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u0435\u0442\u0441\u044F <em>(upadi\u1E63\u1E6De)</em> \u0442\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435 <em>(katha\xF1cid)</em>, \u043E\u0442\u043F\u0435\u0447\u0430\u0442\u043A\u0430 [\u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u015Aiva] <em>(v\u0101san\u0101)</em> \u043D\u0435 <em>(na eva)</em> \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(j\u0101yate... iti)</em>&quot;||</p></blockquote><p>[\u041F\u043E\u0437\u0436\u0435, \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E \u0432 M\u0101lin\u012Bvijayatantra, \u0447\u0442\u043E]</p><blockquote><p>&quot;[\u041E\u0434\u043D\u0430\u043A\u043E,] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E <em>(ya\u1E25... tam)</em> \u043D\u0435 <em>(na)</em> \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(j\u0101yate)</em> \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C <em>(apramatta\u1E25)</em>, \u0434\u0430\u0436\u0435 \u043A\u043E\u0433\u0434\u0430 <em>(api)</em> \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 --\u043F\u0440\u0438 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0438-- <em>(l\u0101bhe)</em> \u043F\u0440\u043E\u0441\u0442\u043E <em>(m\u0101tra)</em> \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u044B\u0445 \u043E\u0442\u043F\u0435\u0447\u0430\u0442\u043A\u043E\u0432, [\u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0445 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u043B\u0430\u043C\u0438] <em>(v\u0101san\u0101)</em>, Vin\u0101yaka-s --\u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 \u0442\u0438\u043F \u0434\u0435\u043C\u043E\u043D\u043E\u0432-- <em>(vin\u0101yak\u0101\u1E25)</em> \u043F\u043E\u0431\u0443\u0436\u0434\u0430\u044E\u0442 \u0438 \u043F\u0440\u0438\u043D\u0443\u0436\u0434\u0430\u044E\u0442 <em>(yojayanti)</em> \u043A \u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0438\u043C <em>(anitye\u1E63u)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F\u043C <em>(bhoge\u1E63u... iti)</em>&quot;||</p></blockquote><p>\u0422\u0435 \u0436\u0435 \u0441\u0430\u043C\u044B\u0435 [\u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F] <em>(tad etad)</em> \u0431\u044B\u043B\u0438 \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u044B <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u044D\u0442\u0438\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C] <em>(anena)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em>:</p><blockquote><p>&quot;\u0412 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(anyath\u0101 tu)</em><sup>4</sup>, \u0441\u0438\u043B\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(s\u1E5B\u1E63\u1E6Di\u1E25)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0435\u0435 <em>(tad)</em> \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430\u043C <em>(dharmakatvata\u1E25)</em>, \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(sy\u0101t)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(satatam)</em> \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0439 <em>(svatantr\u0101)</em> [\u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C] \u043A\u0430\u043A <em>(iva)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439 <em>(laukikasya)</em>, \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0434\u0432\u0443\u0445 <em>(dvaye)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 <em>(pada)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101grat)</em> [\u0438] \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 <em>(svapna)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s III, 3]</p></blockquote><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 [\u043F\u0440\u0438\u0447\u0438\u043D\u0435] <em>(atas ca)</em>, \u044D\u0442\u043E <em>(bhavati)</em> \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u0435\u0442\u0441\u044F <em>(upadi\u1E63\u1E6Dam)</em> [\u043A\u0430\u043A] &quot;[\u0430\u043A\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u0432 \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435] \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C\u0441\u044F <em>(nityam... bh\u0101vyam)</em> Yog\u012B <em>(yogin\u0101)</em>, \u0433\u043B\u0430\u0432\u043D\u044B\u043C \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E <em>(pare\u1E47a eva)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0435 <em>(vimar\u015Bana)</em> \u0427\u0438\u0441\u0442\u043E\u0433\u043E <em>(\u015Buddha)</em> \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101... iti)</em>&quot;|</p><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(yath\u0101-uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C P\u016Brva --\u0442.\u0435. \u0432 M\u0101lin\u012Bvijayatantra-- <em>(\u015Br\u012B-p\u016Brve)</em> --\u0432 \u0442\u0440\u0435\u0442\u044C\u0435\u0439 \u0441\u0442\u0440\u043E\u043A\u0435, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u0435\u0442 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0443\u044E \u0441\u0442\u0440\u043E\u0444\u0443, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 &quot;[\u041E\u0434\u043D\u0430\u043A\u043E,] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043D\u0435 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C...&quot;--:</p><blockquote><p>&quot;\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tasm\u0101t)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0441\u0432\u043E\u0435\u0433\u043E] \u0436\u0435\u043B\u0430\u043D\u0438\u044F <em>(v\u0101\xF1chay\u0101)</em> [\u0434\u043E\u0441\u0442\u0438\u0447\u044C] \u0412\u044B\u0441\u0448\u0443\u044E \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(uttama)</em>, [\u0442\u0430\u043A\u043E\u043C\u0443 Yog\u012B] \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0441\u0442\u0443\u043F\u0430\u0442\u044C \u0432 \u0442\u0435\u0441\u043D\u044B\u0439 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 <em>(na... sa\u1E41saktim kurv\u012Bta)</em> \u0441 \u044D\u0442\u0438\u043C\u0438 [\u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0438 \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F\u043C\u0438] <em>(te\u1E63u... iti)</em>&quot;|</p></blockquote><p>\u0422\u0430\u043A\u0436\u0435 <em>(api)</em>, \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em> [\u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E:]</p><blockquote><p>&quot;\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas)</em>, \u0442\u043E\u0442, \u043A\u0442\u043E \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(satatam)</em> \u0433\u043E\u0442\u043E\u0432 <em>(udyukta\u1E25)</em> \u043A \u0440\u0430\u0441\u043F\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044E <em>(viviktaye)</em> \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(tattva)</em> \u0421\u043F\u0430\u043D\u0434\u044B <em>(spanda)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(adhigacchati)</em> \u0441\u0432\u043E\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(nijam)</em> [\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0433\u043E] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u0438\u043B\u0438 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(bh\u0101vam)</em> \u0431\u044B\u0441\u0442\u0440\u043E <em>(acire\u1E47a)</em>, [\u0434\u0430\u0436\u0435 \u0432] (\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438) \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101grat eva... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 21]</p></blockquote><p>\u0422\u0430\u043A <em>(evam)</em>, [\u0412\u0442\u043E\u0440\u0430\u044F \u0413\u043B\u0430\u0432\u0430,] \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u044D\u0442\u043E\u0433\u043E [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430] <em>(atas prabh\u1E5Bti)</em>: &quot;\u0423\u043C [\u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 \u043D\u0430\u0434 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E] <em>(cittam)</em> [\u0435\u0441\u0442\u044C] \u041C\u0430\u043D\u0442\u0440\u0430 <em>(mantra\u1E25... iti)</em>&quot; \u2014\u0430\u0444\u043E\u0440\u0438\u0437\u043C 1 \u0432\u0442\u043E\u0440\u043E\u0439 \u0413\u043B\u0430\u0432\u044B <em>(2-1)</em>\u2014, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 [\u0432 \u043F\u0435\u0440\u0432\u0443\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C] --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, &quot;\u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u043A\u0430\u0437\u0430&quot;, \u0438\u043B\u0438 &quot;\u043F\u043E\u043A\u0430\u0437&quot;-- <em>(vivicya)</em>, \u0447\u0442\u043E \u015A\u0101ktop\u0101ya <em>(\u015B\u0101kta-up\u0101yam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043E\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u043E\u0432\u0430\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C\u0438 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u043C\u0438 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u043C\u0438 --\u0100gama-s-- <em>(\u0101mn\u0101tam)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:]</p><blockquote><p>&quot;\u0422\u043E\u0442, \u043A\u0442\u043E \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 <em>(vicintayan)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0441\u0432\u043E\u0435\u0433\u043E] \u0443\u043C\u0430 <em>(cetas\u0101 eva)</em> \u043D\u0430\u0434 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(vastu)</em>, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E <em>(rahitam)</em> \u0432\u044B\u0440\u0430\u0437\u0438\u0442\u044C \u0441\u043B\u043E\u0432\u0430\u043C\u0438 <em>(ucc\u0101ra)</em> , \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(\u0101pnoti)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F [\u0432 \u0412\u044B\u0441\u0448\u0435\u043C \u042F] <em>(yam sam\u0101ve\u015Bam)</em>. \u0417\u0434\u0435\u0441\u044C <em>(atra)</em>, \u044D\u0442\u043E [\u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435] <em>(sa\u1E25)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C <em>(abhidh\u012Byate)</em> \u043A\u0430\u043A \u015B\u0101kta --\u0442.\u0435. \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u0435 \u0447\u0435\u0440\u0435\u0437 \u015A\u0101ktop\u0101ya-- <em>(\u015B\u0101kta\u1E25... iti)</em>&quot;||<br> [\u0421\u043C. M\u0101lin\u012Bvijayatantra II, 22]</p></blockquote><p>\u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F <em>(pradh\u0101nam)</em> \u043A \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u043C\u0443 \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044E <em>(anusandhi)</em> \u0441\u0438\u043B\u044B <em>(v\u012Brya... v\u012Brya)</em> \u043C\u0430\u043D\u0442\u0440\u044B \u0438 \u043C\u0443\u0434\u0440\u044B <em>(mantra... mudr\u0101)</em>. [\u041F\u043E\u0437\u0436\u0435,] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E] \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 [\u0442\u0435\u043A\u0443\u0449\u0435\u0439 \u0413\u043B\u0430\u0432\u044B] <em>(s\u016Btre\u1E47a)</em> \u2014\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 10 \u0432\u0442\u043E\u0440\u043E\u0439 \u0413\u043B\u0430\u0432\u044B <em>(2-10)</em>\u2014: &quot;\u041F\u0440\u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0438 <em>(sa\u1E41h\u0101re)</em> [\u0427\u0438\u0441\u0442\u043E\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em> \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 [\u043A\u0430\u043A \u0432\u043E \u0441\u043D\u0435] <em>(svapna)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0445 <em>(uttha)</em> \u0438\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E <em>(tad... iti)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C, &quot;\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0445 \u0438\u0437-\u0437\u0430 \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F&quot;]&quot;, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0431\u0440\u0430\u0449\u0435\u043D <em>(prati)</em> \u043A [\u0438\u0441\u043A\u0430\u0442\u0435\u043B\u044E] \u0441\u043E \u0441\u043B\u0430\u0431\u044B\u043C \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435\u043C <em>(avadh\u0101na-avaliptam)</em>, \u0432 \u044D\u0442\u043E\u0439 \u0441\u0432\u044F\u0437\u0438 <em>(etad-anu\u1E63a\u1E45ge\u1E47a)</em> \u0434\u0430\u0435\u0442\u0441\u044F <em>(datta\u1E25)</em> \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C <em>(avak\u0101\u015Ba\u1E25)</em> \u0434\u043B\u044F \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F <em>(pratip\u0101danasya)</em> \u0100\u1E47avop\u0101ya <em>(\u0101\u1E47ava-up\u0101ya)</em>, [\u0442.\u0435. \u0443\u043F\u0430\u0439\u0438 <em>(up\u0101ya)</em>, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0439 \u0413\u043B\u0430\u0432\u0435]<sup>5</sup>|</p><p>\u0414\u0430 \u0431\u0443\u0434\u0435\u0442 \u0431\u043B\u0430\u0433\u043E [\u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432] <em>(iti \u015Bivam)</em>!||10||</p><hr><ol><li><p>\u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 \u0435\u0441\u0442\u044C \u043D\u0438\u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0435 \u2014 \u044D\u0442\u043E \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u043F\u0435\u0440\u0432\u043E\u0433\u043E. \u0415\u0441\u043B\u0438 \u043A\u0442\u043E-\u0442\u043E \u0441\u0447\u0438\u0442\u0430\u0435\u0442, \u0447\u0442\u043E \u043E\u0431\u0430 \u043E\u0442\u043B\u0438\u0447\u043D\u044B \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430, \u0437\u043D\u0430\u0447\u0438\u0442 \u043E\u043D \u0435\u0449\u0435 \u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043B \u0441\u0443\u0442\u0438 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438.</p></li><li><p>\u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u043C\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u0431\u044B\u043B \u0430\u0434\u0430\u043F\u0442\u0438\u0440\u043E\u0432\u0430\u043D, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u043E\u0433\u043E \u044F\u0437\u044B\u043A\u0430 \u043D\u0435 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u043E\u0439, \u0447\u0442\u043E \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435. \u0411\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u044D\u0442\u043E \u0437\u0432\u0443\u0447\u0438\u0442 \u0442\u0430\u043A: &quot;tadutthasya kram\u0101tkramanyakk\u1E5Btavidy\u0101sa\u1E41sk\u0101rasya&quot; - &quot;\u0438\u0437 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0438\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E, \u0442\u043E\u0433\u043E, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0435 \u043E\u0442\u043F\u0435\u0447\u0430\u0442\u043A\u0438/ \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F \u043E\u0442 \u0417\u043D\u0430\u043D\u0438\u044F \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442&quot;. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u043D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435, \u043D\u043E \u0442\u0440\u0443\u0434\u043D\u043E \u0447\u0438\u0442\u0430\u0442\u044C \u043D\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u043E\u043C, \u043C\u043D\u0435 \u043F\u0440\u0438\u0448\u043B\u043E\u0441\u044C \u0432\u044B\u0441\u0442\u0440\u043E\u0438\u0442\u044C \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043F\u043E \u0434\u0440\u0443\u0433\u043E\u043C\u0443, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0434\u043B\u044F \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044F \u0441\u043C\u044B\u0441\u043B\u0430 \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C \u0442\u0435\u0440\u043C\u0438\u043D\u044B \u0432 \u043A\u0440\u0443\u0433\u043B\u044B\u0445 \u0441\u043A\u043E\u0431\u043A\u0430\u0445: &quot;[\u042D\u0442\u043E\u0442 svapna] \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0438\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u0435 \u043E\u0442\u043F\u0435\u0447\u0430\u0442\u043A\u0438/\u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F [\u0427\u0438\u0441\u0442\u043E\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F \u0443\u0433\u0430\u0441\u0430\u044E\u0442 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E&quot;.</p></li><li><p>\u0424\u0440\u0430\u0437\u0430 &quot;Na ca... aprasannena&quot;, \u043A\u043E\u0433\u0434\u0430 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442: &quot;\u041D\u0435... \u0442\u0435\u043C, \u043A\u0442\u043E \u043D\u0435 \u0434\u043E\u0432\u043E\u043B\u0435\u043D&quot;. \u0427\u0430\u0441\u0442\u0438\u0446\u0430 &quot;ca&quot; \u043D\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0437\u0434\u0435\u0441\u044C &quot;\u0438&quot; (\u0441\u043E\u044E\u0437), \u043D\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043F\u0440\u043E\u0441\u0442\u043E \u043A\u0430\u043A \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u0430\u044F, \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u044F \u0432\u044B\u0440\u0430\u0437\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u043E\u0441\u0442\u0430\u0432\u0430\u044F\u0441\u044C \u043D\u0435 \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0439. \u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u043A\u043E\u0433\u0434\u0430 \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u043A\u043E\u043C\u0431\u0438\u043D\u0430\u0446\u0438\u044F &quot;na + na&quot; \u0438\u043B\u0438 &quot;na +\u043F\u0440\u0438\u0432\u0430\u0442\u0438\u0432\u043D\u0430\u044F \u0447\u0430\u0441\u0442\u0438\u0446\u0430&quot;, \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u043B\u044C\u043D\u043E\u0435 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435. \u041F\u0440\u0438\u0432\u0430\u0442\u0438\u0432\u043D\u0430\u044F \u0447\u0430\u0441\u0442\u0438\u0446\u0430 \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u2014 \u044D\u0442\u043E &quot;a&quot;\u0432 &quot;a-prasannena&quot;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0432\u0441\u0435 \u0432 \u0443\u0442\u0432\u0435\u0440\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u0438 \u0434\u043E\u0431\u0430\u0432\u0438\u043B &quot;\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E&quot; \u0440\u0430\u0434\u0438 \u0431\u043E\u043B\u044C\u0448\u0435\u0433\u043E \u0430\u043A\u0446\u0435\u043D\u0442\u0430: &quot;\u043A\u043E\u0433\u0434\u0430 \u041E\u043D \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0434\u043E\u0432\u043E\u043B\u0435\u043D!&quot;. \u041D\u0443 \u0445\u043E\u0440\u043E\u0448\u043E, \u043F\u0440\u043E\u0441\u0442\u043E \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u0434\u043B\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0445 \u0437\u043D\u0430\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u0441\u0434\u0435\u043B\u0430\u043B \u0432\u0441\u0435 \u044D\u0442\u043E.</p></li><li><p>&quot;\u0412 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435&quot;, \u0442\u043E \u0435\u0441\u0442\u044C, &quot;\u043A\u043E\u0433\u0434\u0430 Yog\u012B \u043F\u0440\u0435\u043D\u0435\u0431\u0440\u0435\u0433\u0430\u0435\u0442 \u0435\u0433\u043E \u043C\u043E\u043B\u044C\u0431\u043E\u0439 \u0438 \u043F\u0435\u0440\u0435\u0441\u0442\u0430\u0435\u0442 \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u0442\u044C \u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443&quot;.</p></li><li><p>\u041F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u044D\u0442\u043E\u0439 \u0413\u043B\u0430\u0432\u044B \u0434\u0430\u0435\u0442 \u0431\u043B\u0430\u0433\u043E\u043F\u0440\u0438\u044F\u0442\u043D\u0443\u044E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C, \u0438\u043B\u0438 \u0441\u043B\u0443\u0447\u0430\u0439 (anu\u1E63a\u1E45ga) \u0434\u043B\u044F \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0100\u1E47avop\u0101ya, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 , \u0447\u0442\u043E \u015Auddhavidy\u0101, \u0438\u043B\u0438 \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 \u0438\u0441\u0447\u0435\u0437\u043B\u043E. \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E \u0432\u0430\u0436\u043D\u043E \u0434\u043B\u044F \u0443\u0441\u043F\u0435\u0445\u0430 \u0432 \u015A\u0101ktop\u0101ya, \u043D\u043E \u0438\u0441\u043A\u0430\u0442\u0435\u043B\u044C, \u0447\u044C\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0441\u043B\u0430\u0431\u043E\u0435, \u0442\u0435\u0440\u044F\u0435\u0442 \u0442\u043E\u0447\u043A\u0443 \u0437\u0440\u0435\u043D\u0438\u044F \u044D\u0442\u043E\u0439 \u015Auddhavidy\u0101. \u0422\u043E\u0433\u0434\u0430, \u043A \u043A\u0430\u043A\u043E\u043C\u0443 \u043C\u0435\u0442\u043E\u0434\u0443, \u0438\u043B\u0438 up\u0101ya \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0435\u0442 \u0438\u0441\u043A\u0430\u0442\u0435\u043B\u044C? \u041E\u0442\u0432\u0435\u0442 \u043D\u0430 \u044D\u0442\u043E: \u043A \u0100\u1E47avop\u0101ya. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li></ol></div><div class="stanza"><h2 id="\u043A\u043E\u043D\u0435\u0446-\u0433n\u0430\u0432\u044B-ii" tabindex="-1">\u041A\u043E\u043D\u0435\u0446 \u0413\u043B\u0430\u0432\u044B II <a class="header-anchor" href="#\u043A\u043E\u043D\u0435\u0446-\u0433n\u0430\u0432\u044B-ii" aria-hidden="true">#</a></h2><div class="sans"><p>\u0906\u0926\u093F\u0924\u0903 \u0938\u0942\u0924\u094D\u0930\u0938\u0919\u094D\u0916\u094D\u092F\u093E\u0965\u0969\u0968\u0965</p><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u0928\u094D\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u093E\u091A\u093E\u0930\u094D\u092F\u093E\u092D\u093F\u0928\u0935\u0917\u0941\u092A\u094D\u0924\u092A\u093E\u0926\u092A\u0926\u094D\u092E\u094B\u092A\u091C\u0940\u0935\u093F\u0936\u094D\u0930\u0940\u0915\u094D\u0937\u0947\u092E\u0930\u093E\u091C\u0935\u093F\u0930\u091A\u093F\u0924\u093E\u092F\u093E\u0902 \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u093F\u0928\u094D\u092F\u093E\u0902 \u0936\u093E\u0915\u094D\u0924\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u0915\u093E\u0936\u0928\u0902 \u0928\u093E\u092E \u0926\u094D\u0935\u093F\u0924\u0940\u092F \u0909\u0928\u094D\u092E\u0947\u0937\u0903\u0965\u0968\u0965</p></div><hr><div class="trans"><p>\u0100dita\u1E25 s\u016Btrasa\u1E45khy\u0101||32||</p><p>Iti \u015Br\u012Bmanm\u0101he\u015Bvar\u0101c\u0101ry\u0101bhinavaguptap\u0101dapadmopaj\u012Bvi\u015Br\u012Bk\u1E63emar\u0101javiracit\u0101y\u0101\u1E41 \u015Bivas\u016Btravimar\u015Biny\u0101\u1E41 \u015B\u0101ktop\u0101yaprak\u0101\u015Bana\u1E41 n\u0101ma dvit\u012Bya unme\u1E63a\u1E25||2||</p></div><hr><p>\u0421 \u0441\u0430\u043C\u043E\u0433\u043E \u043D\u0430\u0447\u0430\u043B\u0430 [\u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(\u0101dita\u1E25)</em>, \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E <em>(sa\u1E45khy\u0101)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u0432 <em>(s\u016Btra)</em> [\u0442\u0435\u043F\u0435\u0440\u044C \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442] \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u044C \u0434\u0432\u0430 <em>(32)</em> --22 \u0432 \u043F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u0435 \u0438 10 \u0432\u043E \u0432\u0442\u043E\u0440\u043E\u0439 \u0413\u043B\u0430\u0432\u0435--||</p><p>\u0417\u0434\u0435\u0441\u044C \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(iti)</em> \u0432\u0442\u043E\u0440\u0430\u044F <em>(dvit\u012Bya\u1E25)</em> \u0413\u043B\u0430\u0432\u0430 <em>(unme\u1E63a\u1E25)</em>, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F <em>(n\u0101ma)</em> \u015A\u0101ktop\u0101yaprak\u0101\u015Bana --[\u0413\u043B\u0430\u0432\u0430], \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u043C\u0435\u0442\u043E\u0434\u044B, \u0438\u043C\u0435\u044E\u0449\u0438\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u043A \u015Aakti-- <em>(\u015B\u0101kta-up\u0101ya-prak\u0101\u015Banam)</em>, \u0432 \u0428\u0438\u0432\u0430\u0441\u0443\u0442\u0440\u0430\u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438 <em>(\u015Bivas\u016Btravimar\u015Biny\u0101m)</em>, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u0430\u044F <em>(viracit\u0101y\u0101m)</em> \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u044B\u043C <em>(\u015Br\u012B)</em> K\u1E63emar\u0101ja <em>(k\u1E63emar\u0101ja)</em>, \u0437\u0430\u0432\u0438\u0441\u044F\u0449\u0438\u043C \u043E\u0442 <em>(upaj\u012Bvi)</em> \u043B\u043E\u0442\u043E\u0441\u043D\u044B\u0445 \u0441\u0442\u043E\u043F --\u0442.\u0435. \u0441\u0442\u043E\u043F, \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0445 \u043A\u0430\u043A \u043B\u043E\u0442\u043E\u0441-- <em>(p\u0101da-padma)</em> \u0432\u044B\u0434\u0430\u044E\u0449\u0435\u0433\u043E\u0441\u044F <em>(\u015Br\u012Bmat)</em> \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0430 <em>(\u0101c\u0101rya)</em> \u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u044B <em>(abhinavagupta)</em>, \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0433\u043E Mahe\u015Bvara, \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 --\u044D\u043F\u0438\u0442\u0435\u0442 \u015Aiva-- <em>(m\u0101he\u015Bvara)</em>||2||</p></div>',2),o=[i];function u(n,r,s,v,d,y){return m(),e("div",null,o)}var q=a(p,[["render",u]]);export{c as __pageData,q as default};
